<template><div class="document-page" v-loading="loading"><div class="document-header"><div><el-button link @click="router.back()"><el-icon><ArrowLeft/></el-icon> 返回</el-button><h1>新增{{isOut?'借出':'借入'}}单</h1></div><div><el-button @click="router.push(basePath)">取消</el-button><el-button type="primary" :loading="saving" @click="submit">保存草稿</el-button></div></div><el-alert :title="isOut?'审核后商品将从所选仓库借出并减少库存。':'审核后借入商品将进入所选仓库并增加库存。'" :type="isOut?'warning':'info'" show-icon :closable="false" class="alert"/><el-card><template #header><div class="section-title"><span>基本信息</span><small>填写借用日期、仓库和往来单位</small></div></template><el-form ref="formRef" :model="form" :rules="rules" label-position="top"><el-row :gutter="20"><el-col :span="6"><el-form-item label="借用日期" prop="borrowDate"><el-date-picker v-model="form.borrowDate" type="date" value-format="YYYY-MM-DD" style="width:100%"/></el-form-item></el-col><el-col :span="6"><el-form-item label="预计归还"><el-date-picker v-model="form.expectedReturnDate" type="date" value-format="YYYY-MM-DD" style="width:100%"/></el-form-item></el-col><el-col :span="6"><el-form-item label="仓库" prop="warehouseId"><el-select v-model="form.warehouseId" style="width:100%"><el-option v-for="w in warehouses" :key="w.value" :label="w.label" :value="w.value"/></el-select></el-form-item></el-col><el-col :span="6"><el-form-item label="单位类型"><el-select v-model="form.partnerType" style="width:100%" @change="resetPartner"><el-option label="客户" value="CUSTOMER"/><el-option label="供应商" value="SUPPLIER"/><el-option label="其他单位" value="OTHER"/></el-select></el-form-item></el-col><el-col :span="12"><el-form-item label="往来单位" required><el-select v-if="form.partnerType!=='OTHER'" v-model="form.partnerId" filterable style="width:100%" @change="selectPartner"><el-option v-for="p in partners" :key="p.value" :label="p.label" :value="p.value"/></el-select><el-input v-else v-model="form.partnerName" maxlength="200"/></el-form-item></el-col><el-col :span="12"><el-form-item label="备注"><el-input v-model="form.remark"/></el-form-item></el-col></el-row></el-form></el-card><el-card class="section-card"><template #header><div class="detail-head"><div class="section-title"><span>借用商品</span><small>{{isOut?'借出数量不能超过可用库存':'借入商品需填写参考成本'}}</small></div><el-button type="primary" plain @click="addItem">+ 添加商品</el-button></div></template><el-table :data="form.items" border><el-table-column type="index" label="序号" width="60"/><el-table-column label="商品" min-width="270"><template #default="{row}"><el-select v-model="row.productId" filterable style="width:100%"><el-option v-for="p in products" :key="p.value" :label="p.label" :value="p.value"/></el-select></template></el-table-column><el-table-column v-if="isOut" label="可用库存" width="110" align="right"><template #default="{row}">{{quantity(stockMap[row.productId])}}</template></el-table-column><el-table-column label="借用数量" width="170"><template #default="{row}"><el-input-number v-model="row.quantity" :min="0.0001" :precision="4" style="width:145px"/></template></el-table-column><el-table-column v-if="!isOut" label="参考成本" width="170"><template #default="{row}"><el-input-number v-model="row.unitCost" :min="0" :precision="4" style="width:145px"/></template></el-table-column><el-table-column label="备注" min-width="180"><template #default="{row}"><el-input v-model="row.remark"/></template></el-table-column><el-table-column label="操作" width="75"><template #default="{$index}"><el-button link type="danger" @click="form.items.splice($index,1)">删除</el-button></template></el-table-column></el-table><el-empty v-if="!form.items.length" description="暂无商品，请点击右上角添加"/></el-card></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref,watch}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage}from'element-plus';import{createInventoryBorrow,getStocks}from'@/api/inventory';import{getCustomerOptions,getProductOptions,getSupplierOptions,getWarehouseOptions}from'@/api/masterdata';const route=useRoute(),router=useRouter(),type=computed(()=>String(route.meta.borrowType||'BORROW_OUT')),isOut=computed(()=>type.value==='BORROW_OUT'),basePath=computed(()=>isOut.value?'/inventory/borrow-outs':'/inventory/borrow-ins'),loading=ref(false),saving=ref(false),formRef=ref(),warehouses=ref<any[]>([]),products=ref<any[]>([]),customers=ref<any[]>([]),suppliers=ref<any[]>([]),stockMap=ref<Record<number,number>>({}),form=reactive<any>({borrowType:type.value,borrowDate:today(),expectedReturnDate:plusDays(7),warehouseId:null,partnerType:isOut.value?'CUSTOMER':'SUPPLIER',partnerId:null,partnerName:'',remark:'',items:[]}),partners=computed(()=>form.partnerType==='CUSTOMER'?customers.value:suppliers.value),rules={borrowDate:[{required:true,message:'请选择借用日期',trigger:'change'}],warehouseId:[{required:true,message:'请选择仓库',trigger:'change'}]};onMounted(async()=>{loading.value=true;try{const[w,p,c,s]=await Promise.all([getWarehouseOptions(),getProductOptions(),getCustomerOptions(),getSupplierOptions()]);warehouses.value=w.data||[];products.value=p.data||[];customers.value=c.data||[];suppliers.value=s.data||[];addItem()}finally{loading.value=false}});watch(()=>form.warehouseId,async id=>{stockMap.value={};if(!id)return;const r=await getStocks({page:1,size:1000,warehouseId:id});stockMap.value=Object.fromEntries((r.data.records||[]).map((s:any)=>[s.productId,Number(s.availableQuantity||0)]))});function today(){return new Date().toISOString().slice(0,10)}function plusDays(n:number){const d=new Date();d.setDate(d.getDate()+n);return d.toISOString().slice(0,10)}function quantity(v:any){return Number(v||0).toFixed(4).replace(/\.?0+$/,'')||'0'}function resetPartner(){form.partnerId=null;form.partnerName=''}function selectPartner(id:number){form.partnerName=partners.value.find((i:any)=>i.value===id)?.label||''}function addItem(){form.items.push({productId:null,quantity:1,unitCost:0,remark:''})}async function submit(){if(!await formRef.value.validate().catch(()=>false))return;if(!form.partnerName?.trim())return ElMessage.warning('请选择或填写往来单位');if(form.expectedReturnDate&&form.expectedReturnDate<form.borrowDate)return ElMessage.warning('预计归还日期不能早于借用日期');if(!form.items.length||form.items.some((i:any)=>!i.productId||Number(i.quantity)<=0))return ElMessage.warning('请完整填写至少一条借用商品');if(new Set(form.items.map((i:any)=>i.productId)).size!==form.items.length)return ElMessage.warning('同一商品不能重复添加');if(isOut.value&&form.items.some((i:any)=>Number(i.quantity)>Number(stockMap.value[i.productId]||0)))return ElMessage.warning('借出数量不能超过可用库存');saving.value=true;try{const r=await createInventoryBorrow(form);ElMessage.success(`${isOut.value?'借出':'借入'}单已保存`);router.replace(`${basePath.value}/${r.data.id}`)}finally{saving.value=false}}</script>
<style scoped>.document-page{padding-bottom:24px}.document-header{min-height:66px;display:flex;align-items:center;justify-content:space-between;margin:-16px -20px 16px;padding:0 22px;background:#fff;border-bottom:1px solid #edf0f5}.document-header>div,.section-title,.detail-head{display:flex;align-items:center;gap:10px}.document-header h1{margin:0;font-size:19px}.alert{margin-bottom:14px}.section-card{margin-top:14px}.section-title{gap:12px}.section-title span{font-size:16px;font-weight:600}.section-title small{color:#a1a8b3}.detail-head{justify-content:space-between}</style>
